import json

def lambda_handler(event, context):
    # Parse Bedrock request
    request_body = json.loads(event['requestBody'])
    query = request_body['inputText']

    # Mock retrieval from knowledge base
    retrieved_docs = [
        {'content': 'Q3 launch features AI analytics...', 'metadata': {'source': 'q3-report.pdf', 'page': 5}},
        {'content': 'New pricing model introduced...', 'metadata': {'source': 'pricing.pdf', 'page': 12}}
    ]

    # Re-rank by relevance (semantic similarity)
    reranked_docs = sorted(retrieved_docs, key=lambda x: len(query.split()) / len(x['content'].split()), reverse=True)[:3]

    response = {
        'retrievedDocuments': [
            {
                'content': {'text': doc['content']},
                'metadata': {'relevanceScore': 0.95, 'source': doc['metadata']['source']}
            } for doc in reranked_docs
        ],
        'citations': [{'generatedTextChunkIndex': 0, 'sourceTextChunkIndex': 0}]
    }

    return {
        'responseBody': json.dumps(response),
        'sessionState': {'promptSession': {'sessionAttributes': {'query_history': query}}},
        'statusCode': 200
    }

import { BedrockAgentRuntimeClient, InvokeAgentCommand, GetAgentInvocationCommand } from '@aws-sdk/client-bedrock-agent-runtime';

const client = new BedrockAgentRuntimeClient({ region: 'us-east-1' });

const agentId = 'YOUR_AGENT_ID';
const agentAliasId = 'YOUR_AGENT_ALIAS_ID';
const sessionId = `session-${Date.now()}`;

interface AgentResponse {
  completion: string;
  citations?: Array<{generatedTextChunkIndex: number; sourceTextChunkIndex: number}>;
}

async function invokeBedrockAgent(query: string): Promise<AgentResponse> {
  const invokeParams = {
    agentId,
    agentAliasId,
    sessionId,
    inputText: query,
    enableTrace: true,
  };

  const invokeCommand = new InvokeAgentCommand(invokeParams);
  const invokeResponse = await client.send(invokeCommand);

  const getCommand = new GetAgentInvocationCommand({
    agentId,
    agentAliasId,
    sessionId,
    invocationId: invokeResponse.invocationId!,
  });

  const completionResponse = await client.send(getCommand);
  return {
    completion: completionResponse.completion!,
    citations: completionResponse.citations,
  };
}

// Usage
(async () => {
  const response = await invokeBedrockAgent('Summarize Q3 financials');
  console.log(response);
})();

import boto3
from typing import List, Dict

kb_client = boto3.client('bedrock-agent-runtime')

def retrieve_from_kb(knowledge_base_id: str, query: str, filter_pattern: str = None) -> List[Dict]:
    retrieval_config = {
        'vectorSearchConfiguration': {
            'numberOfResults': 5,
            'overrideSearchType': 'HYBRID',
            'filterPattern': filter_pattern  # e.g., "metadata.department:finance"
        }
    }

    response = kb_client.retrieve(
        knowledgeBaseId=knowledge_base_id,
        retrievalQuery={'text': query},
        retrievalConfiguration=retrieval_config
    )

    return [
        {
            'content': result['content']['text'],
            'metadata': result['metadata'],
            'score': result.get('score', 0.0),
            'location': result['location']['type']
        }
        for result in response['retrievalResults']
    ]

# Usage
docs = retrieve_from_kb('YOUR_KB_ID', 'Q3 revenue growth', 'metadata.year:"2024"')

