import { verify } from 'vex-sdk';

type AgentOutput = {
  completion: string;
  citations: Array<{generatedTextChunkIndex: number; sourceTextChunkIndex: number}>;
  sources: Array<{content: string; metadata: {source: string}}>
};

const verifier = verify({
  checks: ['citation_accuracy', 'source_faithfulness'],
  riskProfile: 'high',
  customMetrics: {
    citation_coverage: ({citations, sources}) => citations.length / sources.length
  }
});

export async function verifyRagOutput(output: AgentOutput): Promise<boolean> {
  const result = await verifier.verify({
    input: output.completion,
    context: output.sources.map(s => s.content).join('\n'),
    metadata: {
      citations: output.citations,
      source_count: output.sources.length
    }
  });

  return result.passed && result.metrics.citation_coverage > 0.8;
}

// Usage
