        "context_relevance",
        "session_state_consistency",
        "temporal_reasoning"
    ]
)
def multi_turn_agent(query: str, session_state: Dict[str, Any], docs: list) -> Dict:
    return {
        "response": f"Answering: {query}",
        "session_state": {
            **session_state,
            "turn_count": session_state.get('turn_count', 0) + 1,
            "recent_docs": [d['metadata']['source'] for d in docs[-3:]]
        },
        "citations": len(docs)
    }

# Conversation loop
def chat_loop():
    session_state = {"turn_count": 0}

    for query in ["What is Q3 revenue?", "How does it compare to Q2?"]:
        docs = retrieve_from_kb('kb-id', query)
        result = multi_turn_agent(query, session_state, docs)
        session_state = result['session_state']
        print(result['response'])

